        try:
            with open("config/config.yaml", encoding="utf-8") as f:
                config = yaml.safe_load(f)
            mock_config = config.get("tianyan", {}).get("mock_mode", True)
            return cast(bool, mock_config)
        except Exception:
            return True  # 默认使用 Mock 模式

